    int i, j, common;

    for (i = 0; i < 5; i++) {
        for (j = 0; j < 5; j++) {
            if (array1[i] == array2[j]) {
                common = i;
                break;
            }
        }
        if (common != -1) {
            printf("Common element: %d\n", common);
            break;
        }
    }

    return 0;
}
```
